import{_ as l,o as e,c as a,ae as o}from"./chunks/framework.C7FLYIpo.js";const m=JSON.parse('{"title":"기능 추가 (기여자 가이드)","description":"OpenClaw 플러그인 시스템에 새로운 공유 기능을 추가하기 위한 기여자 가이드","frontmatter":{"title":"기능 추가 (기여자 가이드)","description":"OpenClaw 플러그인 시스템에 새로운 공유 기능을 추가하기 위한 기여자 가이드"},"headers":[],"relativePath":"tools/capability-cookbook.md","filePath":"tools/capability-cookbook.md","lastUpdated":null}'),t={name:"tools/capability-cookbook.md"};function c(r,i,d,s,p,n){return e(),a("div",null,[...i[0]||(i[0]=[o('<h1 id="기능-추가" tabindex="-1">기능 추가 <a class="header-anchor" href="#기능-추가" aria-label="Permalink to &quot;기능 추가&quot;">​</a></h1><div class="info custom-block"><p class="custom-block-title">INFO</p><p>이것은 OpenClaw 코어 개발자를 위한 <strong>기여자 가이드</strong>입니다. 외부 플러그인을 개발하는 경우, 대신 <a href="/openclaw-docs-ko/plugins/building-plugins">플러그인 개발</a>을 참조하십시오.</p></div><p>이미지 생성, 비디오 생성, 또는 일부 미래의 벤더 기반 기능 영역과 같은 새로운 도메인이 OpenClaw에 필요할 때 사용하십시오.</p><p>규칙:</p><ul><li>플러그인 = 소유권 경계</li><li>기능 = 공유 코어 계약</li></ul><p>즉, 벤더를 채널이나 도구에 직접 연결하는 것부터 시작해서는 안 됩니다. 기능을 정의하는 것부터 시작하십시오.</p><h2 id="기능-생성-시기" tabindex="-1">기능 생성 시기 <a class="header-anchor" href="#기능-생성-시기" aria-label="Permalink to &quot;기능 생성 시기&quot;">​</a></h2><p>다음 조건이 모두 충족될 때 새 기능을 생성합니다:</p><ol><li>둘 이상의 벤더가 구현할 수 있는 경우</li><li>채널, 도구, 또는 기능 플러그인이 벤더에 관계없이 소비할 수 있어야 하는 경우</li><li>코어가 폴백, 정책, 설정, 또는 전달 동작을 소유해야 하는 경우</li></ol><p>벤더 전용 작업이고 아직 공유 계약이 없는 경우, 먼저 계약을 정의하십시오.</p><h2 id="표준-순서" tabindex="-1">표준 순서 <a class="header-anchor" href="#표준-순서" aria-label="Permalink to &quot;표준 순서&quot;">​</a></h2><ol><li>타입이 지정된 코어 계약을 정의합니다.</li><li>해당 계약에 대한 플러그인 등록을 추가합니다.</li><li>공유 런타임 헬퍼를 추가합니다.</li><li>하나의 실제 벤더 플러그인을 증거로 연결합니다.</li><li>기능/채널 소비자를 런타임 헬퍼로 이전합니다.</li><li>계약 테스트를 추가합니다.</li><li>운영자용 설정 및 소유권 모델을 문서화합니다.</li></ol><h2 id="어디에-무엇이-들어가는지" tabindex="-1">어디에 무엇이 들어가는지 <a class="header-anchor" href="#어디에-무엇이-들어가는지" aria-label="Permalink to &quot;어디에 무엇이 들어가는지&quot;">​</a></h2><p>코어:</p><ul><li>요청/응답 타입</li><li>프로바이더 레지스트리 + 해결</li><li>폴백 동작</li><li>중첩된 객체, 와일드카드, 배열 항목, 구성 노드에 전파된 <code>title</code> / <code>description</code> 문서 메타데이터가 있는 설정 스키마</li><li>런타임 헬퍼 표면</li></ul><p>벤더 플러그인:</p><ul><li>벤더 API 호출</li><li>벤더 인증 처리</li><li>벤더별 요청 정규화</li><li>기능 구현 등록</li></ul><p>기능/채널 플러그인:</p><ul><li><code>api.runtime.*</code> 또는 일치하는 <code>plugin-sdk/*-runtime</code> 헬퍼 호출</li><li>벤더 구현을 직접 호출하지 않음</li></ul><h2 id="파일-체크리스트" tabindex="-1">파일 체크리스트 <a class="header-anchor" href="#파일-체크리스트" aria-label="Permalink to &quot;파일 체크리스트&quot;">​</a></h2><p>새 기능의 경우 다음 영역을 수정해야 합니다:</p><ul><li><code>src/&amp;lt;capability&amp;gt;/types.ts</code></li><li><code>src/&amp;lt;capability&amp;gt;/...registry/runtime.ts</code></li><li><code>src/plugins/types.ts</code></li><li><code>src/plugins/registry.ts</code></li><li><code>src/plugins/captured-registration.ts</code></li><li><code>src/plugins/contracts/registry.ts</code></li><li><code>src/plugins/runtime/types-core.ts</code></li><li><code>src/plugins/runtime/index.ts</code></li><li><code>src/plugin-sdk/&amp;lt;capability&amp;gt;.ts</code></li><li><code>src/plugin-sdk/&amp;lt;capability&amp;gt;-runtime.ts</code></li><li>하나 이상의 번들 플러그인 패키지</li><li>설정/문서/테스트</li></ul><h2 id="예시-이미지-생성" tabindex="-1">예시: 이미지 생성 <a class="header-anchor" href="#예시-이미지-생성" aria-label="Permalink to &quot;예시: 이미지 생성&quot;">​</a></h2><p>이미지 생성은 표준 형태를 따릅니다:</p><ol><li>코어가 <code>ImageGenerationProvider</code>를 정의합니다</li><li>코어가 <code>registerImageGenerationProvider(...)</code>를 노출합니다</li><li>코어가 <code>runtime.imageGeneration.generate(...)</code>를 노출합니다</li><li><code>openai</code>, <code>google</code>, <code>fal</code>, <code>minimax</code> 플러그인이 벤더 기반 구현을 등록합니다</li><li>미래 벤더는 채널/도구를 변경하지 않고 동일한 계약을 등록할 수 있습니다</li></ol><p>설정 키는 비전 분석 라우팅과 구분됩니다:</p><ul><li><code>agents.defaults.imageModel</code> = 이미지 분석</li><li><code>agents.defaults.imageGenerationModel</code> = 이미지 생성</li></ul><p>폴백과 정책이 명시적으로 유지되도록 이 두 가지를 구분하십시오.</p><h2 id="검토-체크리스트" tabindex="-1">검토 체크리스트 <a class="header-anchor" href="#검토-체크리스트" aria-label="Permalink to &quot;검토 체크리스트&quot;">​</a></h2><p>새 기능을 출시하기 전에 다음을 확인하십시오:</p><ul><li>채널/도구가 벤더 코드를 직접 임포트하지 않음</li><li>런타임 헬퍼가 공유 경로임</li><li>최소 하나의 계약 테스트가 번들된 소유권을 검증함</li><li>설정 문서에 새 모델/설정 키가 명시됨</li><li>플러그인 문서에 소유권 경계가 설명됨</li></ul><p>PR이 기능 계층을 건너뛰고 채널/도구에 벤더 동작을 하드코딩하면, 계약을 먼저 정의하도록 반려하십시오.</p>',32)])])}const h=l(t,[["render",c]]);export{m as __pageData,h as default};
